template-STD_FIL.scripts:
							function validate_fecha(pObj)
{
  if((Ctrl('fecha_D').GetXValue()!='') && (Ctrl('fecha_H').GetXValue()!=''))
  {
	  if(Ctrl('fecha_D').GetXValue() > Ctrl('fecha_H').GetXValue())
	  {
	    pObj.SetError('La Fecha Desde no puede ser superior a la Fecha Hasta');
	    return false;
	  }
	  else
	  	{
	  	return true;
	  	}
	} 

	return true;
}

