FROM LEG06_RENDICIONES, ( SELECT A.oi_adelanto, A.oi_carpeta, A.f_adelanto, A.n_monto_adel, C.oi_empresa, C.c_carpeta, C.d_carpeta, S.c_sujeto, S.d_sujeto, SUC.c_ubicacion, SUC.d_ubicacion FROM LEG04_ADELANTOS as A, LEG40_CLASIF_SUJ as CS, LEG40_SUJETOS as S, LEG01_CARPETAS as C, ORG03_UBICACIONES as SUC JOIN S.oi_sujeto INNER CS.oi_sujeto, A.oi_clasif_sujeto INNER CS.oi_clasif_sujeto, A.oi_carpeta LEFT OUTER C.oi_carpeta, A.oi_ubicacion INNER SUC.oi_ubicacion
