) %} {% %} %}
{%?($FILTER/@oi_empresa!='') {%and EMP.oi_empresa = {$FILTER/@oi_empresa} %} {% %} %} {%?($FILTER/@oi_carpeta!='') {%and ADELANTO.oi_carpeta = {$FILTER/@oi_carpeta} %} {% %} %}
{%?($FILTER/@oi_adelanto!='') {%and ADELANTO.oi_adelanto = {$FILTER/@oi_adelanto} %} {% %} %}
